def _select_tip_with_weights(self):
    """Select a tip key from TIPS using self.tip_weights to bias the draw.

    Nonpositive or missing weights are treated as 0.0 / 1.0 respectively; if all
    resulting weights are zero, falls back to a uniform draw over TIPS keys.
    """
    keys = list(TIPS.keys())
    weights = [max(self.tip_weights.get(key, 1.0), 0.0) for key in keys]
    total_weight = sum(weights)
    if total_weight <= 0:
        return self.rng.choice(keys)

    threshold = self.rng.random() * total_weight
    cumulative = 0.0
    for key, weight in zip(keys, weights):
        cumulative += weight
        if threshold < cumulative:
            return key
    return keys[-1]

